async function reviewActivation(
  request: AgenticChatRequest,
  runtime: AgenticChatRuntime,
  candidate: ToolCandidate,
  userMessage: string,
  currentMessages: AgenticChatMessage[],
  thothGateTelemetry?: ThothGateTelemetryMetrics,
): Promise<
  | { action: 'accept' }
  | { action: 'cancel'; reason?: string }
  | { action: 'modify'; modifiedArgs: Record<string, unknown> }
> {
  if (candidate.skipReview) return { action: 'accept' };
  const reviewMessages: AgenticChatMessage[] = [
    ...currentMessages,
    {
      role: 'system',
      content: `Review this heuristic tool activation.
Tool: ${candidate.toolName}
User request: ${userMessage}
Suggested args: ${JSON.stringify(candidate.suggestedArgs)}
Thoth gate action hint: ${
        thothGateTelemetry
          ? thothGateTelemetryActionHint(thothGateTelemetry)
          : 'none'
      }

Respond with exactly one:
ACCEPT
MODIFY {"key":"value"}
CANCEL`,
    },
  ];
  const result = await runtime.infer({
    model: request.model,
    messages: reviewMessages,
    temperature: 0,
    maxTokens: 80,
    responseFormat: { type: 'text' },
    round: 0,
    purpose: 'tool-review',
  });
  const normalized = result.content.trim().toUpperCase();
  if (normalized.startsWith('CANCEL')) return { action: 'cancel' };
  if (normalized.startsWith('MODIFY')) {
    const json = result.content.match(/\{[\s\S]*\}/u);
    if (json) {
      try {
        return {
          action: 'modify',
          modifiedArgs: JSON.parse(json[0]) as Record<string, unknown>,
        };
      } catch {
        return { action: 'accept' };
      }
    }
  }
  return { action: 'accept' };
}

async function resolveToolArgs(
  request: AgenticChatRequest,
  runtime: AgenticChatRuntime,
  candidate: ToolCandidate,
  userMessage: string,
  currentMessages: AgenticChatMessage[],
): Promise<Record<string, unknown>> {
  if (Object.keys(candidate.suggestedArgs).length > 0) {
    return candidate.suggestedArgs;
  }
  const result = await runtime.infer({
    model: request.model,
    messages: [
      ...currentMessages,
      {
        role: 'system',
        content: `Craft JSON arguments for tool "${candidate.toolName}".
User request: ${userMessage}
Return only a JSON object.`,
      },
    ],
    temperature: 0,
    maxTokens: 120,
    responseFormat: { type: 'json_object' },
    round: 0,
    purpose: 'tool-args',
  });
  const json = result.content.match(/\{[\s\S]*\}/u);
  if (!json) return {};
  try {
    return JSON.parse(json[0]) as Record<string, unknown>;
  } catch {
    return {};
  }
}

async function executeToolWithValidation(args: {
  toolCall: AgenticToolCall;
  mcp?: AgenticMcpClient;
  runtime: AgenticChatRuntime;
  request: AgenticChatRequest;
  currentMessages: AgenticChatMessage[];
  originalUserMessage: string;
  validateToolResults: boolean;
  maxValidationRetries: number;
  trace: AgenticTraceEntry[];
}): Promise<ToolExecutionResult> {
  const parsedArgs = parseToolArguments(args.toolCall.function.arguments);
  const mcp = args.mcp ?? args.runtime.mcp;
  if (!mcp) {
    return {
      toolCallId: args.toolCall.id,
      toolName: args.toolCall.function.name,
      args: parsedArgs,
      result: null,
      success: false,
      durationMs: 0,
      error: 'No MCP client configured',
    };
  }

  let currentArgs = parsedArgs;
  let bestResult: ToolExecutionResult | null = null;
  let bestQuality = -1;

  for (let attempt = 0; attempt < args.maxValidationRetries; attempt += 1) {
    const result = await mcp.callTool(
      args.toolCall.function.name,
      currentArgs,
      { toolCallId: args.toolCall.id },
    );
    recordThothOathTelemetryTrace(args.trace, result);
    const validation = args.validateToolResults
      ? validateToolResult(result.toolName, currentArgs, result)
      : { valid: true, quality: 1, issues: [], suggestRetry: false };
    args.trace.push({
      layer: 'C3',
      message: 'Tool result validated',
      data: {
        toolName: result.toolName,
        quality: roundScore(validation.quality),
        valid: validation.valid,
        issues: validation.issues,
        attempt: attempt + 1,
      },
    });

    if (validation.quality > bestQuality) {
      bestQuality = validation.quality;
      bestResult = result;
    }
    if (validation.valid || !validation.suggestRetry) {
      return result;
    }
    if (validation.modifiedArgs) {
      currentArgs = validation.modifiedArgs;
      continue;
    }
    if (attempt < args.maxValidationRetries - 1) {
      currentArgs = await refineToolArgsAfterValidation(
        args.request,
        args.runtime,
        args.currentMessages,
        args.originalUserMessage,
        result.toolName,
        currentArgs,
        validation,
      );
    }
  }

  return bestResult!;
}

function recordThothOathTelemetryTrace(
  trace: AgenticTraceEntry[],
  result: ToolExecutionResult,
): void {
  const payload = isRecord(result.result) ? result.result : null;
  const rawEvents = payload?.telemetryEvents ?? payload?.telemetryEvent;
  const events = Array.isArray(rawEvents) ? rawEvents : rawEvents ? [rawEvents] : [];
  for (const event of events.filter(isRecord)) {
    const kind = typeof event.kind === 'string' ? event.kind : 'unknown';
    trace.push({
      layer: 'C4',
      message: `Thoth oath telemetry observed: ${kind}`,
      data: {
        toolName: result.toolName,
        kind,
        oathId: typeof event.oathId === 'string' ? event.oathId : null,
        effectiveStatus:
          typeof event.effectiveStatus === 'string' ? event.effectiveStatus : null,
        activeOathCount:
          typeof event.activeOathCount === 'number' ? event.activeOathCount : null,
        nonAuthoritative: event.nonAuthoritative === true,
        theoremRef: typeof event.theoremRef === 'string' ? event.theoremRef : null,
      },
    });
  }
}

function validateToolResult(
  toolName: string,
  toolArgs: Record<string, unknown>,
  result: ToolExecutionResult,
): ResultValidation {
  if (!result.success || result.error) {
    return {
      valid: false,
      quality: 0,
      issues: [result.error ?? 'Tool execution failed'],
      suggestRetry: isRetryableToolError(result.error),
    };
  }
  if (result.result === null || result.result === undefined) {
    return {
      valid: false,
      quality: 0,
      issues: ['Tool returned no result'],
      suggestRetry: true,
    };
  }

  const serialized =
    typeof result.result === 'string'
      ? result.result
      : JSON.stringify(result.result);
  if (serialized.length < 3) {
    return {
      valid: false,
      quality: 0.2,
      issues: ['Tool result is too short to be useful'],
      suggestRetry: true,
    };
  }
  if (toolName.includes('search') && !hasSearchSignal(result.result)) {
    return {
      valid: false,
      quality: 0.45,
      issues: ['Search-like tool returned no recognizable hits'],
      suggestRetry: false,
    };
  }
  if (
    toolName.includes('summarize') &&
    typeof toolArgs.text === 'string' &&
    serialized.length >= toolArgs.text.length
  ) {
    return {
      valid: false,
      quality: 0.5,
      issues: ['Summary is not shorter than source text'],
      suggestRetry: false,
    };
  }

  return { valid: true, quality: 1, issues: [], suggestRetry: false };
}

function isRetryableToolError(error: string | undefined): boolean {
  if (!error) return false;
  const normalized = error.toLowerCase();
  return (
    normalized.includes('timeout') ||
    normalized.includes('rate') ||
    normalized.includes('invalid') ||
    normalized.includes('too large')
  );
}

function hasSearchSignal(value: unknown): boolean {
  if (Array.isArray(value)) return value.length > 0;
  if (!isRecord(value)) return true;
  for (const key of ['results', 'tools', 'backends', 'matches', 'items']) {
    const field = value[key];
    if (Array.isArray(field) && field.length > 0) return true;
  }
  return Object.keys(value).length > 0;
}

async function refineToolArgsAfterValidation(
  request: AgenticChatRequest,
  runtime: AgenticChatRuntime,
  currentMessages: AgenticChatMessage[],
  originalUserMessage: string,
  toolName: string,
  previousArgs: Record<string, unknown>,
  validation: ResultValidation,
): Promise<Record<string, unknown>> {
  const result = await runtime.infer({
    model: request.model,
    messages: [
      ...currentMessages,
      {
        role: 'system',
        content: `Tool "${toolName}" returned a low-quality result.
Issues: ${validation.issues.join(', ')}
Previous args: ${JSON.stringify(previousArgs)}
User request: ${originalUserMessage}

Return improved arguments as JSON only.`,
      },
    ],
    temperature: 0,
    maxTokens: 120,
    responseFormat: { type: 'json_object' },
    round: 0,
    purpose: 'tool-retry',
  });
  const json = result.content.match(/\{[\s\S]*\}/u);
  if (!json) return previousArgs;
  try {
    return JSON.parse(json[0]) as Record<string, unknown>;
  } catch {
    return previousArgs;
  }
}

function appendToolExchange(
  messages: AgenticChatMessage[],
  toolCall: AgenticToolCall,
  result: ToolExecutionResult,
): void {
  messages.push({
    role: 'assistant',
    content: null,
    tool_calls: [toolCall],
  });
  messages.push({
    role: 'tool',
    tool_call_id: toolCall.id,
    name: result.toolName,
    content: serializeToolResult(result),
  });
}

function serializeToolResult(result: ToolExecutionResult): string {
  if (result.error) {
    return JSON.stringify({ error: result.error });
  }
  return typeof result.result === 'string'
    ? result.result
    : JSON.stringify(result.result);
}

function parseToolArguments(value: string): Record<string, unknown> {
  try {
    const parsed = JSON.parse(value);
    return isRecord(parsed) ? parsed : {};
  } catch {
    return {};
  }
}

function buildToolCall(
  name: string,
  toolArgs: Record<string, unknown>,
  randomId: (prefix: string) => string,
): AgenticToolCall {
  return {
    id: randomId('call'),
    type: 'function',
    function: {
      name,
      arguments: JSON.stringify(toolArgs),
    },
  };
}

function parseToolCalls(
  output: string,
  validToolNames?: Set<string>,
): { text: string; toolCalls: AgenticToolCall[] | null } {
  const toolCalls: AgenticToolCall[] = [];
  let text = output;
  const blockRegex = /```(?:tool_call|json)?\s*\n?\s*(\{[\s\S]*?\})\s*\n?```/gu;
  let match: RegExpExecArray | null;
  while ((match = blockRegex.exec(output)) !== null) {
    const parsed = parseToolCallObject(match[1]);
    if (parsed && (!validToolNames || validToolNames.has(parsed.name))) {
      toolCalls.push({
        id: createId('call'),
        type: 'function',
        function: {
          name: parsed.name,
          arguments: JSON.stringify(parsed.arguments),
        },
      });
      text = text.replace(match[0], '').trim();
    }
  }

  if (toolCalls.length === 0) {
    const rawRegex =
      /\{\s*"name"\s*:\s*"([^"]+)"\s*,\s*"arguments"\s*:\s*(\{[^}]*\})\s*\}/gu;
    while ((match = rawRegex.exec(output)) !== null) {
      const name = match[1]!;
      if (validToolNames && !validToolNames.has(name)) continue;
      try {
        const args = JSON.parse(match[2]!);
        toolCalls.push({
          id: createId('call'),
          type: 'function',
          function: {
            name,
            arguments: JSON.stringify(isRecord(args) ? args : {}),
          },
        });
        text = text.replace(match[0], '').trim();
      } catch {
        // Ignore malformed raw tool JSON.
      }
    }
  }

  return {
    text: text.trim(),
    toolCalls: toolCalls.length > 0 ? toolCalls : null,
  };
}

function parseToolCallObject(
  value: string | undefined,
): { name: string; arguments: Record<string, unknown> } | null {
  if (!value) return null;
  try {
    const parsed = JSON.parse(value);
    if (!isRecord(parsed) || typeof parsed.name !== 'string') return null;
    return {
      name: parsed.name,
      arguments: isRecord(parsed.arguments) ? parsed.arguments : {},
    };
  } catch {
    return null;
  }
}

async function evaluateIntentSatisfaction(
  request: AgenticChatRequest,
  runtime: AgenticChatRuntime,
  originalUserMessage: string,
  currentMessages: AgenticChatMessage[],
  lastToolResults: ToolExecutionResult[],
): Promise<IntentEvaluation> {
  const toolSummary =
    lastToolResults.length === 0
      ? '(no tool results)'
      : lastToolResults
          .map((result) =>
            `${result.toolName}: ${
              result.error ? `ERROR ${result.error}` : serializeToolResult(result)
            }`,
          )
          .join('\n');
  const result = await runtime.infer({
    model: request.model,
    messages: [
      {
        role: 'system',
        content:
          'Evaluate whether the assistant has fully satisfied the user request. Respond with JSON only.',
      },
      {
        role: 'user',
        content: `Original request:
${originalUserMessage}

Conversation:
${renderMessagesForPrompt(currentMessages).slice(-6000)}

Tool results:
${toolSummary}

Return {"satisfied": boolean, "confidence": number, "reasoning": string, "suggestedNextAction": string}.`,
      },
    ],
    temperature: 0,
    maxTokens: 160,
    responseFormat: { type: 'json_object' },
    round: 0,
    purpose: 'intent-evaluation',
  });
  const json = result.content.match(/\{[\s\S]*\}/u);
  if (!json) {
    return inferIntentFromText(result.content);
  }
  try {
    const parsed = JSON.parse(json[0]);
    return {
      satisfied: Boolean(parsed.satisfied),
      confidence:
        typeof parsed.confidence === 'number' ? parsed.confidence : 0.5,
      reasoning:
        typeof parsed.reasoning === 'string'
          ? parsed.reasoning
          : 'No reasoning provided',
      ...(typeof parsed.suggestedNextAction === 'string'
        ? { suggestedNextAction: parsed.suggestedNextAction }
        : {}),
    };
  } catch {
    return inferIntentFromText(result.content);
  }
}

function inferIntentFromText(value: string): IntentEvaluation {
  const normalized = value.toLowerCase();
  if (
    normalized.includes('satisfied') ||
    normalized.includes('complete') ||
    normalized.includes('fully addressed')
  ) {
    return { satisfied: true, confidence: 0.7, reasoning: value.slice(0, 120) };
  }
  return {
    satisfied: false,
    confidence: 0.5,
    reasoning: value.slice(0, 120) || 'Unable to determine satisfaction',
  };
}

function continuationNudgeWithTelemetry(
  evaluation: IntentEvaluation,
  metrics: ThothGateTelemetryMetrics | undefined,
): string {
  const base = continuationNudge(evaluation);
  if (!metrics) return base;
  return `${base}
Thoth gate hint: ${thothGateTelemetryActionHint(metrics)}. Keep any action non-authoritative and source-backed.`;
}

function continuationNudge(evaluation: IntentEvaluation): string {
  if (evaluation.suggestedNextAction) {
    return `The user's request may not be fully addressed yet. Consider: ${evaluation.suggestedNextAction}`;
  }
  return "The user's request may not be fully addressed yet. Continue with the next useful step.";
}

function getLastUserMessage(messages: AgenticChatMessage[]): string {
  for (let index = messages.length - 1; index >= 0; index -= 1) {
    const message = messages[index]!;
    if (message.role === 'user' && typeof message.content === 'string') {
      return message.content;
    }
  }
  return '';
}

function estimateTokensFromMessages(messages: AgenticChatMessage[]): number {
  return estimateTokens(renderMessagesForPrompt(messages));
}

function estimateTokens(value: string): number {
  return Math.max(1, Math.ceil(value.length / 4));
}

function roundScore(value: number): number {
  return Math.round(value * 1000) / 1000;
}

function createId(prefix: string): string {
  if (typeof crypto !== 'undefined' && typeof crypto.randomUUID === 'function') {
    return `${prefix}_${crypto.randomUUID().slice(0, 12)}`;
  }
  return `${prefix}_${Date.now().toString(36)}_${Math.random()
    .toString(36)
    .slice(2, 8)}`;
}

function isRecord(value: unknown): value is Record<string, unknown> {
  return typeof value === 'object' && value !== null && !Array.isArray(value);
}
